import UIKit

class ViewController: UIViewController, UISceneDelegate {

    override func viewDidLoad() {
        super.viewDidLoad()
        // Do any additional setup after loading the view.
        
        // Check if there is a universal link to handle
        if let url = self.view.window?.windowScene?.sceneDelegate as? SceneDelegate,
           let sceneSession = url.sceneSession,
           let userInfo = sceneSession.stateRestorationActivityUserInfo {
            if let universalLink = userInfo[UIUserActivityTypeBrowsingWeb] as? URL {
                handleUniversalLink(universalLink)
            }
        }
    }
    
    func handleUniversalLink(_ link: URL) {
        guard let components = URLComponents(url: link, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems,
              let promoCodeItem = queryItems.first(where: { $0.name == "code" }),
              let discountItem = queryItems.first(where: { $0.name == "discount" }) else {
            print("Invalid URL or missing parameters")
            return
        }
        
        guard let promoCode = promoCodeItem.value,
              let discountString = discountItem.value,
              let discount = Int(discountString) else {
            print("Failed to extract promo code or discount")
            return
        }
        
        // Apply promo code and discount to user account
        applyPromoCode(promoCode: promoCode, discount: discount)
    }
    
    func applyPromoCode(promoCode: String, discount: Int) {
        // Placeholder for applying promo code and discount logic
        print("Applying promo code: \(promoCode) with discount: \(discount)%")
        
        // Example: Save the promo code and discount to user defaults or a database
        UserDefaults.standard.set(promoCode, forKey: "PromoCode")
        UserDefaults.standard.set(discount, forKey: "Discount")
    }
}

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    var sceneSession: UISceneSession?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let _ = (scene as? UIWindowScene) else { return }
        
        // Save the scene session
        self.sceneSession = session
        
        // Check for incoming URLs
        if let urlContexts = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContexts.url)
        }
    }
    
    func handleIncomingURL(_ url: URL) {
        // Forward the URL to the view controller or relevant handler
        print("Handling universal link: \(url)")
        
        if let rootViewController = window?.rootViewController as? ViewController {
            rootViewController.handleUniversalLink(url)
        }
    }
}